package com.example.gestion_mobilek

import android.content.ContentValues
import android.content.Context
import android.database.Cursor
import android.database.sqlite.SQLiteDatabase
import java.net.Inet4Address
import java.net.InetAddress
import java.text.Normalizer
import java.sql.Connection
import java.sql.DriverManager
import java.sql.SQLException

object ExternalMariaDbSync {

    private data class ResolvedTable(
        val localTable: String,
        val remoteTable: String
    )

    data class ColumnMapping(
        val localColumn: String,
        val remoteColumn: String
    )

    data class TableDiagnostic(
        val localTable: String,
        val remoteTable: String?,
        val localColumns: List<String>,
        val remoteColumns: List<String>,
        val mappedColumns: List<ColumnMapping>,
        val ignoredLocalColumns: List<String>,
        val ignoredRemoteColumns: List<String>
    )

    data class OnlineDiagnosticReport(
        val host: String,
        val port: Int,
        val configuredDatabase: String?,
        val resolvedDatabase: String,
        val tables: List<TableDiagnostic>,
        val notes: List<String>
    )

    private data class MariaDbConfig(
        val host: String,
        val port: Int,
        val user: String,
        val password: String,
        val forcedDatabase: String?
    )

    private val syncTables = listOf(
        "personnes",
        "gouts",
        "ingrédient",
        "plats",
        "repas",
        "future_repas",
        "future_repas_rappels"
    )
    private val optionalRemoteTables = setOf("future_repas", "future_repas_rappels")
    private val requiredRemoteTables = syncTables.toSet() - optionalRemoteTables
    private val coreTables = setOf("personnes", "gouts", "plats")
    private val tableAliases = mapOf(
        "ingrédient" to listOf("ingredient", "ingredients", "ingrdient"),
        "plats" to listOf("plat"),
        "future_repas" to listOf("future_recette", "future_recettes", "futur_repas", "futurs_repas"),
        "future_repas_rappels" to listOf("future_rappels", "rappels_future_repas", "future_recette_rappels", "rappels_future_recettes")
    )
    private val columnAliases = mapOf(
        "nom_plat" to listOf("nom", "plat"),
        "nom_ingredient" to listOf("nom", "ingredient"),
        "date_dernier_repas" to listOf("date_repas"),
        "date_repas" to listOf("date_dernier_repas"),
        "id_personnes" to listOf("id_personne", "personnes", "ids_personnes")
    )

    private fun escapeIdent(name: String): String = "`" + name.replace("`", "``") + "`"

    private fun isLikelyIpAddress(host: String): Boolean {
        return host.matches(Regex("^\\d+\\.\\d+\\.\\d+\\.\\d+$")) || host.contains(":")
    }

    private fun connectionHosts(host: String): List<String> {
        if (isLikelyIpAddress(host)) return listOf(host)
        val resolvedV4 = runCatching {
            InetAddress.getAllByName(host)
                .filterIsInstance<Inet4Address>()
                .mapNotNull { it.hostAddress }
        }.getOrDefault(emptyList())

        return listOf(host) + resolvedV4
    }

    private fun jdbcUrl(host: String, port: Int, database: String?): String {
        val dbSegment = database?.let { "/${escapeDbPath(it)}" } ?: "/"
        return "jdbc:mariadb://$host:$port$dbSegment?connectTimeout=5000&socketTimeout=10000&sslMode=disable"
    }

    private fun openConnectionWithFallback(config: MariaDbConfig, database: String?): Connection {
        Class.forName("org.mariadb.jdbc.Driver")
        var lastError: SQLException? = null

        connectionHosts(config.host).distinct().forEach { hostCandidate ->
            try {
                return DriverManager.getConnection(
                    jdbcUrl(hostCandidate, config.port, database),
                    config.user,
                    config.password
                )
            } catch (e: SQLException) {
                lastError = e
            }
        }

        throw SQLException(
            "Connexion socket impossible vers ${config.host}:${config.port}. " +
                "Verifiez ouverture du port, acces reseau mobile/Wi-Fi et bind MariaDB.",
            lastError
        )
    }

    private fun resolveConfig(): MariaDbConfig {
        val host = BuildConfig.MARIADB_HOST.trim()
        val port = BuildConfig.MARIADB_PORT
        val user = BuildConfig.MARIADB_USER.trim()
        val password = BuildConfig.MARIADB_PASSWORD
        val forcedDatabase = BuildConfig.MARIADB_DATABASE.trim().ifBlank { null }

        if (host.isBlank() || port <= 0 || user.isBlank() || password.isBlank()) {
            throw SQLException("Configuration MariaDB manquante: ajoutez le fichier .env")
        }

        return MariaDbConfig(
            host = host,
            port = port,
            user = user,
            password = password,
            forcedDatabase = forcedDatabase
        )
    }

    private fun openServerConnection(config: MariaDbConfig): Connection {
        return openConnectionWithFallback(config, database = null)
    }

    private fun openDatabaseConnection(config: MariaDbConfig, databaseName: String): Connection {
        return openConnectionWithFallback(config, database = databaseName)
    }

    private fun escapeDbPath(name: String): String {
        // Path segment escaping is intentionally strict for safety.
        return name.replace("`", "")
    }

    private fun normalizeTableName(name: String): String {
        val nfd = Normalizer.normalize(name, Normalizer.Form.NFD)
        return nfd.replace(Regex("\\p{Mn}+"), "")
    }

    private fun remoteTableNames(connection: Connection, dbName: String): Set<String> {
        val sql = "SELECT table_name FROM information_schema.tables WHERE table_schema = ?"
        connection.prepareStatement(sql).use { ps ->
            ps.setString(1, dbName)
            ps.executeQuery().use { rs ->
                val names = mutableSetOf<String>()
                while (rs.next()) {
                    names.add(rs.getString(1))
                }
                return names
            }
        }
    }

    private fun resolveRemoteTableName(localTable: String, remoteNames: Set<String>): String? {
        if (remoteNames.contains(localTable)) return localTable
        val normalizedLocal = normalizeTableName(localTable)

        remoteNames.firstOrNull { normalizeTableName(it).equals(normalizedLocal, ignoreCase = true) }?.let {
            return it
        }

        val candidates = listOf(localTable) + tableAliases[localTable].orEmpty()
        candidates.forEach { candidate ->
            val normalizedCandidate = normalizeTableName(candidate)
            remoteNames.firstOrNull { normalizeTableName(it).equals(normalizedCandidate, ignoreCase = true) }?.let {
                return it
            }
        }
        return null
    }

    private fun remoteTableColumns(connection: Connection, dbName: String, tableName: String): Set<String> {
        val sql = "SELECT column_name FROM information_schema.columns WHERE table_schema = ? AND table_name = ?"
        connection.prepareStatement(sql).use { ps ->
            ps.setString(1, dbName)
            ps.setString(2, tableName)
            ps.executeQuery().use { rs ->
                val cols = mutableSetOf<String>()
                while (rs.next()) {
                    cols.add(rs.getString(1))
                }
                return cols
            }
        }
    }

    private fun resolveRemoteColumnName(localColumn: String, remoteColumns: Set<String>): String? {
        val candidates = listOf(localColumn) + columnAliases[localColumn].orEmpty()
        candidates.forEach { candidate ->
            if (remoteColumns.contains(candidate)) return candidate
            val normalized = normalizeTableName(candidate)
            remoteColumns.firstOrNull { normalizeTableName(it).equals(normalized, ignoreCase = true) }?.let {
                return it
            }
        }
        return null
    }

    private fun resolveLocalColumnName(remoteColumn: String, localColumns: List<String>): String? {
        if (localColumns.contains(remoteColumn)) return remoteColumn
        localColumns.firstOrNull { localColumn ->
            val localCandidates = listOf(localColumn) + columnAliases[localColumn].orEmpty()
            localCandidates.any { candidate ->
                normalizeTableName(candidate).equals(normalizeTableName(remoteColumn), ignoreCase = true)
            }
        }?.let {
            return it
        }

        val normalized = normalizeTableName(remoteColumn)
        return localColumns.firstOrNull { normalizeTableName(it).equals(normalized, ignoreCase = true) }
    }

    private fun localTableHasData(sqliteDb: SQLiteDatabase, table: String): Boolean {
        return runCatching {
            sqliteDb.rawQuery("SELECT 1 FROM ${escapeIdent(table)} LIMIT 1", null).use { it.moveToFirst() }
        }.getOrDefault(false)
    }

    private fun mapTableDiagnostic(
        sqliteDb: SQLiteDatabase,
        remoteConn: Connection,
        databaseName: String,
        localTable: String,
        remoteTable: String?
    ): TableDiagnostic {
        val localColumns = sqliteTableColumns(sqliteDb, localTable)
        val remoteColumns = if (remoteTable != null) {
            remoteTableColumns(remoteConn, databaseName, remoteTable).toList()
        } else {
            emptyList()
        }

        val mappedColumns = if (remoteTable != null) {
            localColumns.mapNotNull { localColumn ->
                resolveRemoteColumnName(localColumn, remoteColumns.toSet())?.let { remoteColumn ->
                    ColumnMapping(localColumn, remoteColumn)
                }
            }
        } else {
            emptyList()
        }

        val ignoredLocalColumns = localColumns.filter { localColumn ->
            mappedColumns.none { it.localColumn == localColumn }
        }
        val ignoredRemoteColumns = remoteColumns.filter { remoteColumn ->
            mappedColumns.none { it.remoteColumn == remoteColumn }
        }

        return TableDiagnostic(
            localTable = localTable,
            remoteTable = remoteTable,
            localColumns = localColumns,
            remoteColumns = remoteColumns,
            mappedColumns = mappedColumns,
            ignoredLocalColumns = ignoredLocalColumns,
            ignoredRemoteColumns = ignoredRemoteColumns
        )
    }

    fun buildOnlineDiagnostic(context: Context): Result<OnlineDiagnosticReport> {
        return runCatching {
            val config = resolveConfig()
            openServerConnection(config).use { serverConn ->
                val resolvedDatabase = resolveDatabaseName(context, config, serverConn)
                openDatabaseConnection(config, resolvedDatabase).use { dbConn ->
                    val sqliteDb = DatabaseHelper(context).getDatabaseForMode(useExternal = true)
                    FutureRecettesManager.ensureSchema(sqliteDb)

                    val remoteNames = remoteTableNames(dbConn, resolvedDatabase)
                    val notes = mutableListOf<String>()
                    if (config.forcedDatabase != null) {
                        notes.add("Base forcee via .env : ${config.forcedDatabase}")
                    } else {
                        notes.add("Base distante detectee automatiquement : $resolvedDatabase")
                    }

                    val tables = syncTables.map { localTable ->
                        val remoteTable = resolveRemoteTableName(localTable, remoteNames)
                        mapTableDiagnostic(sqliteDb, dbConn, resolvedDatabase, localTable, remoteTable)
                    }

                    if (tables.none { it.remoteTable != null }) {
                        notes.add("Aucune table mappable detectee dans la base distante.")
                    }

                    OnlineDiagnosticReport(
                        host = config.host,
                        port = config.port,
                        configuredDatabase = config.forcedDatabase,
                        resolvedDatabase = resolvedDatabase,
                        tables = tables,
                        notes = notes
                    )
                }
            }
        }
    }

    private fun hasAllTargetTables(connection: Connection, dbName: String): Boolean {
        val names = remoteTableNames(connection, dbName)
        return coreTables.all { core -> resolveRemoteTableName(core, names) != null }
    }

    private fun resolveDatabaseName(context: Context, config: MariaDbConfig, connection: Connection): String {
        if (!config.forcedDatabase.isNullOrBlank()) {
            return config.forcedDatabase
        }

        val preferred = SettingsStore.getExternalDatabaseName(context)
        if (!preferred.isNullOrBlank() && hasAllTargetTables(connection, preferred)) {
            return preferred
        }

        val candidates = mutableListOf<String>()
        connection.createStatement().use { statement ->
            statement.executeQuery("SHOW DATABASES").use { rs ->
                while (rs.next()) {
                    val db = rs.getString(1)
                    if (!db.equals("information_schema", true) &&
                        !db.equals("mysql", true) &&
                        !db.equals("performance_schema", true) &&
                        !db.equals("sys", true)
                    ) {
                        candidates.add(db)
                    }
                }
            }
        }

        return candidates.firstOrNull { hasAllTargetTables(connection, it) }
            ?: throw SQLException("Aucune base distante compatible trouvee")
    }

    private fun sqliteTableColumns(sqliteDb: SQLiteDatabase, table: String): List<String> {
        val cols = mutableListOf<String>()
        sqliteDb.rawQuery("PRAGMA table_info(${escapeIdent(table)})", null).use { c ->
            if (c.moveToFirst()) {
                do {
                    cols.add(c.getString(1))
                } while (c.moveToNext())
            }
        }
        return cols
    }

    private fun resultSetValueToContent(values: ContentValues, column: String, raw: Any?) {
        when (raw) {
            null -> values.putNull(column)
            is Int -> values.put(column, raw)
            is Long -> values.put(column, raw)
            is Short -> values.put(column, raw.toInt())
            is Float -> values.put(column, raw)
            is Double -> values.put(column, raw)
            is ByteArray -> values.put(column, raw)
            is Boolean -> values.put(column, if (raw) 1 else 0)
            else -> values.put(column, raw.toString())
        }
    }

    private fun pullTableFromRemote(
        sqliteDb: SQLiteDatabase,
        remoteConn: Connection,
        databaseName: String,
        localTable: String,
        remoteTable: String
    ): Boolean {
        val columns = sqliteTableColumns(sqliteDb, localTable)
        if (columns.isEmpty()) return false
        val remoteColumns = remoteTableColumns(remoteConn, databaseName, remoteTable)

        val mappedColumns = columns.mapNotNull { localColumn ->
            resolveRemoteColumnName(localColumn, remoteColumns)?.let { remoteColumn ->
                localColumn to remoteColumn
            }
        }
        if (mappedColumns.isEmpty()) return false

        val sqlColumns = mappedColumns.joinToString(", ") { (_, remoteColumn) -> escapeIdent(remoteColumn) }
        val query = "SELECT $sqlColumns FROM ${escapeIdent(databaseName)}.${escapeIdent(remoteTable)}"

        sqliteDb.beginTransaction()
        try {
            sqliteDb.delete(localTable, null, null)

            remoteConn.createStatement().use { st ->
                st.executeQuery(query).use { rs ->
                    while (rs.next()) {
                        val values = ContentValues()
                        mappedColumns.forEachIndexed { index, (localColumn, _) ->
                            resultSetValueToContent(values, localColumn, rs.getObject(index + 1))
                        }
                        sqliteDb.insert(localTable, null, values)
                    }
                }
            }

            sqliteDb.setTransactionSuccessful()
        } finally {
            sqliteDb.endTransaction()
        }
        return true
    }

    private fun bindCursorValue(psIndex: Int, cursor: Cursor, colIndex: Int, ps: java.sql.PreparedStatement) {
        when (cursor.getType(colIndex)) {
            Cursor.FIELD_TYPE_NULL -> ps.setObject(psIndex, null)
            Cursor.FIELD_TYPE_INTEGER -> ps.setLong(psIndex, cursor.getLong(colIndex))
            Cursor.FIELD_TYPE_FLOAT -> ps.setDouble(psIndex, cursor.getDouble(colIndex))
            Cursor.FIELD_TYPE_BLOB -> ps.setBytes(psIndex, cursor.getBlob(colIndex))
            else -> ps.setString(psIndex, cursor.getString(colIndex))
        }
    }

    private fun pushTableToRemote(
        sqliteDb: SQLiteDatabase,
        remoteConn: Connection,
        databaseName: String,
        localTable: String,
        remoteTable: String
    ): Boolean {
        val localColumns = sqliteTableColumns(sqliteDb, localTable)
        if (localColumns.isEmpty()) return false
        val remoteColumns = remoteTableColumns(remoteConn, databaseName, remoteTable)

        val mappedColumns = remoteColumns.mapNotNull { remoteColumn ->
            resolveLocalColumnName(remoteColumn, localColumns)?.let { localColumn ->
                localColumn to remoteColumn
            }
        }
        if (mappedColumns.isEmpty()) {
            if (localTableHasData(sqliteDb, localTable)) {
                throw SQLException(
                    "Aucune colonne compatible pour pousser '$localTable' vers '$remoteTable'"
                )
            }
            return false
        }

        val escapedColumns = mappedColumns.joinToString(", ") { (_, remoteColumn) -> escapeIdent(remoteColumn) }
        val placeholders = mappedColumns.joinToString(", ") { "?" }
        val selectColumns = mappedColumns.joinToString(", ") { (localColumn, _) -> escapeIdent(localColumn) }
        val insertSql = "INSERT INTO ${escapeIdent(databaseName)}.${escapeIdent(remoteTable)} ($escapedColumns) VALUES ($placeholders)"
        val selectSql = "SELECT $selectColumns FROM ${escapeIdent(localTable)}"

        try {
            sqliteDb.rawQuery(selectSql, null).use { cursor ->
                remoteConn.prepareStatement(insertSql).use { ps ->
                    if (cursor.moveToFirst()) {
                        do {
                            mappedColumns.indices.forEach { i ->
                                bindCursorValue(i + 1, cursor, i, ps)
                            }
                            ps.addBatch()
                        } while (cursor.moveToNext())
                    }
                    ps.executeBatch()
                }
            }
        } catch (e: SQLException) {
            throw SQLException(
                "Echec insertion table distante '$remoteTable' depuis '$localTable' : ${e.message}",
                e.sqlState,
                e.errorCode,
                e
            )
        }
        return true
    }

    private fun clearRemoteTable(
        remoteConn: Connection,
        databaseName: String,
        remoteTable: String
    ) {
        val deleteSql = "DELETE FROM ${escapeIdent(databaseName)}.${escapeIdent(remoteTable)}"
        try {
            remoteConn.createStatement().use { it.executeUpdate(deleteSql) }
        } catch (e: SQLException) {
            throw SQLException(
                "Echec suppression table distante '$remoteTable' : ${e.message}",
                e.sqlState,
                e.errorCode,
                e
            )
        }
    }

    fun connectAndPull(context: Context): Result<String> {
        return runCatching {
            val config = resolveConfig()
            openServerConnection(config).use { serverConn ->
                val dbName = resolveDatabaseName(context, config, serverConn)
                openDatabaseConnection(config, dbName).use { dbConn ->
                    val sqliteDb = DatabaseHelper(context).getDatabaseForMode(useExternal = true)
                    FutureRecettesManager.ensureSchema(sqliteDb)
                    val remoteNames = remoteTableNames(dbConn, dbName)
                    var synced = 0
                    syncTables.forEach { localTable ->
                        val remoteTable = resolveRemoteTableName(localTable, remoteNames)
                        if (remoteTable != null) {
                            if (pullTableFromRemote(sqliteDb, dbConn, dbName, localTable, remoteTable)) {
                                synced++
                            }
                        }
                    }
                    if (synced == 0) {
                        throw SQLException("Aucune table utilisable trouvee dans la base distante '$dbName'")
                    }
                }
                SettingsStore.setExternalDatabaseName(context, dbName)
                SettingsStore.setExternalDataSourceEnabled(context, true)
                DatabaseHelper.closeActiveDatabase()
                dbName
            }
        }
    }

    fun pushExternalToRemote(context: Context): Result<Int> {
        return runCatching {
            val config = resolveConfig()
            val dbName = SettingsStore.getExternalDatabaseName(context)
                ?: throw SQLException("Nom de base distante introuvable")

            openDatabaseConnection(config, dbName).use { dbConn ->
                dbConn.autoCommit = false
                try {
                    val sqliteDb = DatabaseHelper(context).getDatabaseForMode(useExternal = true)
                    FutureRecettesManager.ensureSchema(sqliteDb)
                    val remoteNames = remoteTableNames(dbConn, dbName)

                    val unresolvedWithData = syncTables.filter { localTable ->
                        resolveRemoteTableName(localTable, remoteNames) == null && localTableHasData(sqliteDb, localTable)
                    }
                    val unresolvedRequiredWithData = unresolvedWithData.filter { it in requiredRemoteTables }
                    if (unresolvedRequiredWithData.isNotEmpty()) {
                        throw SQLException(
                            "Tables distantes requises manquantes pour donnees locales: ${unresolvedRequiredWithData.joinToString(", ")}"
                        )
                    }

                    val resolvedTables = syncTables.mapNotNull { localTable ->
                        resolveRemoteTableName(localTable, remoteNames)?.let { remoteTable ->
                            ResolvedTable(localTable = localTable, remoteTable = remoteTable)
                        }
                    }
                    if (resolvedTables.isEmpty()) {
                        throw SQLException("Aucune table distante mappable trouvee pour '$dbName'")
                    }

                    // Delete children first to satisfy foreign keys, then insert parents first.
                    resolvedTables.asReversed().forEach { table ->
                        clearRemoteTable(dbConn, dbName, table.remoteTable)
                    }

                    var pushed = 0
                    resolvedTables.forEach { table ->
                        if (pushTableToRemote(sqliteDb, dbConn, dbName, table.localTable, table.remoteTable)) {
                            pushed++
                        }
                    }
                    if (pushed == 0) {
                        throw SQLException("Aucune table n'a pu etre synchronisee vers la base distante '$dbName'")
                    }
                    dbConn.commit()
                    pushed
                } catch (e: Exception) {
                    dbConn.rollback()
                    throw e
                } finally {
                    dbConn.autoCommit = true
                }
            }
        }
    }
}

package com.example.gestion_mobilek

import android.content.ContentValues
import android.content.Context
import android.database.Cursor
import android.database.sqlite.SQLiteDatabase
import java.net.Inet4Address
import java.net.InetAddress
import java.text.Normalizer
import java.sql.Connection
import java.sql.DriverManager
import java.sql.SQLException

object ExternalMariaDbSync {

    private data class ResolvedTable(
        val localTable: String,
        val remoteTable: String
    )

    data class ColumnMapping(
        val localColumn: String,
        val remoteColumn: String
    )

    data class TableDiagnostic(
        val localTable: String,
        val remoteTable: String?,
        val localColumns: List<String>,
        val remoteColumns: List<String>,
        val mappedColumns: List<ColumnMapping>,
        val ignoredLocalColumns: List<String>,
        val ignoredRemoteColumns: List<String>
    )

    data class OnlineDiagnosticReport(
        val host: String,
        val port: Int,
        val configuredDatabase: String?,
        val resolvedDatabase: String,
        val tables: List<TableDiagnostic>,
        val notes: List<String>
    )

    private data class MariaDbConfig(
        val host: String,
        val port: Int,
        val user: String,
        val password: String,
        val forcedDatabase: String?
    )

    private val syncTables = listOf(
        "personnes",
        "gouts",
        "ingrédient",
        "plats",
        "repas",
        "future_repas",
        "future_repas_rappels"
    )
    private val optionalRemoteTables = setOf("future_repas", "future_repas_rappels")
    private val requiredRemoteTables = syncTables.toSet() - optionalRemoteTables
    private val coreTables = setOf("personnes", "gouts", "plats")
    private val tableAliases = mapOf(
        "ingrédient" to listOf("ingredient", "ingredients", "ingrdient"),
        "plats" to listOf("plat"),
        "future_repas" to listOf("future_recette", "future_recettes", "futur_repas", "futurs_repas"),
        "future_repas_rappels" to listOf("future_rappels", "rappels_future_repas", "future_recette_rappels", "rappels_future_recettes")
    )
    private val columnAliases = mapOf(
        "nom_plat" to listOf("nom", "plat"),
        "nom_ingredient" to listOf("nom", "ingredient"),
        "date_dernier_repas" to listOf("date_repas"),
        "date_repas" to listOf("date_dernier_repas"),
        "id_personnes" to listOf("id_personne", "personnes", "ids_personnes")
    )

    private fun escapeIdent(name: String): String = "`" + name.replace("`", "``") + "`"

    private fun isLikelyIpAddress(host: String): Boolean {
        return host.matches(Regex("^\\d+\\.\\d+\\.\\d+\\.\\d+$")) || host.contains(":")
    }

    private fun connectionHosts(host: String): List<String> {
        if (isLikelyIpAddress(host)) return listOf(host)
        val resolvedV4 = runCatching {
            InetAddress.getAllByName(host)
                .filterIsInstance<Inet4Address>()
                .mapNotNull { it.hostAddress }
        }.getOrDefault(emptyList())

        return listOf(host) + resolvedV4
    }

    private fun jdbcUrl(host: String, port: Int, database: String?): String {
        val dbSegment = database?.let { "/${escapeDbPath(it)}" } ?: "/"
        return "jdbc:mariadb://$host:$port$dbSegment?connectTimeout=5000&socketTimeout=10000&sslMode=disable"
    }

    private fun openConnectionWithFallback(config: MariaDbConfig, database: String?): Connection {
        Class.forName("org.mariadb.jdbc.Driver")
        var lastError: SQLException? = null

        connectionHosts(config.host).distinct().forEach { hostCandidate ->
            try {
                return DriverManager.getConnection(
                    jdbcUrl(hostCandidate, config.port, database),
                    config.user,
                    config.password
                )
            } catch (e: SQLException) {
                lastError = e
            }
        }

        throw SQLException(
            "Connexion socket impossible vers ${config.host}:${config.port}. " +
                "Verifiez ouverture du port, acces reseau mobile/Wi-Fi et bind MariaDB.",
            lastError
        )
    }

    private fun resolveConfig(): MariaDbConfig {
        val host = BuildConfig.MARIADB_HOST.trim()
        val port = BuildConfig.MARIADB_PORT
        val user = BuildConfig.MARIADB_USER.trim()
        val password = BuildConfig.MARIADB_PASSWORD
        val forcedDatabase = BuildConfig.MARIADB_DATABASE.trim().ifBlank { null }

        if (host.isBlank() || port <= 0 || user.isBlank() || password.isBlank()) {
            throw SQLException("Configuration MariaDB manquante: ajoutez le fichier .env")
        }

        return MariaDbConfig(
            host = host,
            port = port,
            user = user,
            password = password,
            forcedDatabase = forcedDatabase
        )
    }

    private fun openServerConnection(config: MariaDbConfig): Connection {
        return openConnectionWithFallback(config, database = null)
    }

    private fun openDatabaseConnection(config: MariaDbConfig, databaseName: String): Connection {
        return openConnectionWithFallback(config, database = databaseName)
    }

    private fun escapeDbPath(name: String): String {
        // Path segment escaping is intentionally strict for safety.
        return name.replace("`", "")
    }

    private fun normalizeTableName(name: String): String {
        val nfd = Normalizer.normalize(name, Normalizer.Form.NFD)
        return nfd.replace(Regex("\\p{Mn}+"), "")
    }

    private fun remoteTableNames(connection: Connection, dbName: String): Set<String> {
        val sql = "SELECT table_name FROM information_schema.tables WHERE table_schema = ?"
        connection.prepareStatement(sql).use { ps ->
            ps.setString(1, dbName)
            ps.executeQuery().use { rs ->
                val names = mutableSetOf<String>()
                while (rs.next()) {
                    names.add(rs.getString(1))
                }
                return names
            }
        }
    }

    private fun resolveRemoteTableName(localTable: String, remoteNames: Set<String>): String? {
        if (remoteNames.contains(localTable)) return localTable
        val normalizedLocal = normalizeTableName(localTable)

        remoteNames.firstOrNull { normalizeTableName(it).equals(normalizedLocal, ignoreCase = true) }?.let {
            return it
        }

        val candidates = listOf(localTable) + tableAliases[localTable].orEmpty()
        candidates.forEach { candidate ->
            val normalizedCandidate = normalizeTableName(candidate)
            remoteNames.firstOrNull { normalizeTableName(it).equals(normalizedCandidate, ignoreCase = true) }?.let {
                return it
            }
        }
        return null
    }

    private fun remoteTableColumns(connection: Connection, dbName: String, tableName: String): Set<String> {
        val sql = "SELECT column_name FROM information_schema.columns WHERE table_schema = ? AND table_name = ?"
        connection.prepareStatement(sql).use { ps ->
            ps.setString(1, dbName)
            ps.setString(2, tableName)
            ps.executeQuery().use { rs ->
                val cols = mutableSetOf<String>()
                while (rs.next()) {
                    cols.add(rs.getString(1))
                }
                return cols
            }
        }
    }

    private fun resolveRemoteColumnName(localColumn: String, remoteColumns: Set<String>): String? {
        val candidates = listOf(localColumn) + columnAliases[localColumn].orEmpty()
        candidates.forEach { candidate ->
            if (remoteColumns.contains(candidate)) return candidate
            val normalized = normalizeTableName(candidate)
            remoteColumns.firstOrNull { normalizeTableName(it).equals(normalized, ignoreCase = true) }?.let {
                return it
            }
        }
        return null
    }

    private fun resolveLocalColumnName(remoteColumn: String, localColumns: List<String>): String? {
        if (localColumns.contains(remoteColumn)) return remoteColumn
        localColumns.firstOrNull { localColumn ->
            val localCandidates = listOf(localColumn) + columnAliases[localColumn].orEmpty()
            localCandidates.any { candidate ->
                normalizeTableName(candidate).equals(normalizeTableName(remoteColumn), ignoreCase = true)
            }
        }?.let {
            return it
        }

        val normalized = normalizeTableName(remoteColumn)
        return localColumns.firstOrNull { normalizeTableName(it).equals(normalized, ignoreCase = true) }
    }

    private fun localTableHasData(sqliteDb: SQLiteDatabase, table: String): Boolean {
        return runCatching {
            sqliteDb.rawQuery("SELECT 1 FROM ${escapeIdent(table)} LIMIT 1", null).use { it.moveToFirst() }
        }.getOrDefault(false)
    }

    private fun mapTableDiagnostic(
        sqliteDb: SQLiteDatabase,
        remoteConn: Connection,
        databaseName: String,
        localTable: String,
        remoteTable: String?
    ): TableDiagnostic {
        val localColumns = sqliteTableColumns(sqliteDb, localTable)
        val remoteColumns = if (remoteTable != null) {
            remoteTableColumns(remoteConn, databaseName, remoteTable).toList()
        } else {
            emptyList()
        }

        val mappedColumns = if (remoteTable != null) {
            localColumns.mapNotNull { localColumn ->
                resolveRemoteColumnName(localColumn, remoteColumns.toSet())?.let { remoteColumn ->
                    ColumnMapping(localColumn, remoteColumn)
                }
            }
        } else {
            emptyList()
        }

        val ignoredLocalColumns = localColumns.filter { localColumn ->
            mappedColumns.none { it.localColumn == localColumn }
        }
        val ignoredRemoteColumns = remoteColumns.filter { remoteColumn ->
            mappedColumns.none { it.remoteColumn == remoteColumn }
        }

        return TableDiagnostic(
            localTable = localTable,
            remoteTable = remoteTable,
            localColumns = localColumns,
            remoteColumns = remoteColumns,
            mappedColumns = mappedColumns,
            ignoredLocalColumns = ignoredLocalColumns,
            ignoredRemoteColumns = ignoredRemoteColumns
        )
    }

    fun buildOnlineDiagnostic(context: Context): Result<OnlineDiagnosticReport> {
        return runCatching {
            val config = resolveConfig()
            openServerConnection(config).use { serverConn ->
                val resolvedDatabase = resolveDatabaseName(context, config, serverConn)
                openDatabaseConnection(config, resolvedDatabase).use { dbConn ->
                    val sqliteDb = DatabaseHelper(context).getDatabaseForMode(useExternal = true)
                    FutureRecettesManager.ensureSchema(sqliteDb)

                    val remoteNames = remoteTableNames(dbConn, resolvedDatabase)
                    val notes = mutableListOf<String>()
                    if (config.forcedDatabase != null) {
                        notes.add("Base forcee via .env : ${config.forcedDatabase}")
                    } else {
                        notes.add("Base distante detectee automatiquement : $resolvedDatabase")
                    }

                    val tables = syncTables.map { localTable ->
                        val remoteTable = resolveRemoteTableName(localTable, remoteNames)
                        mapTableDiagnostic(sqliteDb, dbConn, resolvedDatabase, localTable, remoteTable)
                    }

                    if (tables.none { it.remoteTable != null }) {
                        notes.add("Aucune table mappable detectee dans la base distante.")
                    }

                    OnlineDiagnosticReport(
                        host = config.host,
                        port = config.port,
                        configuredDatabase = config.forcedDatabase,
                        resolvedDatabase = resolvedDatabase,
                        tables = tables,
                        notes = notes
                    )
                }
            }
        }
    }

    private fun hasAllTargetTables(connection: Connection, dbName: String): Boolean {
        val names = remoteTableNames(connection, dbName)
        return coreTables.all { core -> resolveRemoteTableName(core, names) != null }
    }

    private fun resolveDatabaseName(context: Context, config: MariaDbConfig, connection: Connection): String {
        if (!config.forcedDatabase.isNullOrBlank()) {
            return config.forcedDatabase
        }

        val preferred = SettingsStore.getExternalDatabaseName(context)
        if (!preferred.isNullOrBlank() && hasAllTargetTables(connection, preferred)) {
            return preferred
        }

        val candidates = mutableListOf<String>()
        connection.createStatement().use { statement ->
            statement.executeQuery("SHOW DATABASES").use { rs ->
                while (rs.next()) {
                    val db = rs.getString(1)
                    if (!db.equals("information_schema", true) &&
                        !db.equals("mysql", true) &&
                        !db.equals("performance_schema", true) &&
                        !db.equals("sys", true)
                    ) {
                        candidates.add(db)
                    }
                }
            }
        }

        return candidates.firstOrNull { hasAllTargetTables(connection, it) }
            ?: throw SQLException("Aucune base distante compatible trouvee")
    }

    private fun sqliteTableColumns(sqliteDb: SQLiteDatabase, table: String): List<String> {
        val cols = mutableListOf<String>()
        sqliteDb.rawQuery("PRAGMA table_info(${escapeIdent(table)})", null).use { c ->
            if (c.moveToFirst()) {
                do {
                    cols.add(c.getString(1))
                } while (c.moveToNext())
            }
        }
        return cols
    }

    private fun getLocalPrimaryKey(sqliteDb: SQLiteDatabase, table: String): String? {
        sqliteDb.rawQuery("PRAGMA table_info(${escapeIdent(table)})", null).use { c ->
            val numIdx = c.getColumnIndex("pk")
            val nameIdx = c.getColumnIndex("name")
            if (numIdx >= 0 && nameIdx >= 0 && c.moveToFirst()) {
                do {
                    if (c.getInt(numIdx) > 0) return c.getString(nameIdx)
                } while (c.moveToNext())
            }
        }
        return null
    }

    private fun resultSetValueToContent(values: ContentValues, column: String, raw: Any?) {
        when (raw) {
            null -> values.putNull(column)
            is Int -> values.put(column, raw)
            is Long -> values.put(column, raw)
            is Short -> values.put(column, raw.toInt())
            is Float -> values.put(column, raw)
            is Double -> values.put(column, raw)
            is ByteArray -> values.put(column, raw)
            is Boolean -> values.put(column, if (raw) 1 else 0)
            else -> values.put(column, raw.toString())
        }
    }

    private fun pullTableFromRemote(
        sqliteDb: SQLiteDatabase,
        remoteConn: Connection,
        databaseName: String,
        localTable: String,
        remoteTable: String
    ): Boolean {
        val columns = sqliteTableColumns(sqliteDb, localTable)
        if (columns.isEmpty()) return false
        val remoteColumns = remoteTableColumns(remoteConn, databaseName, remoteTable)

        val mappedColumns = columns.mapNotNull { localColumn ->
            resolveRemoteColumnName(localColumn, remoteColumns)?.let { remoteColumn ->
                localColumn to remoteColumn
            }
        }
        if (mappedColumns.isEmpty()) return false

        val sqlColumns = mappedColumns.joinToString(", ") { (_, remoteColumn) -> escapeIdent(remoteColumn) }
        val query = "SELECT $sqlColumns FROM ${escapeIdent(databaseName)}.${escapeIdent(remoteTable)}"
        val localPk = getLocalPrimaryKey(sqliteDb, localTable)

        sqliteDb.beginTransaction()
        try {
            sqliteDb.delete(localTable, null, null)
            sqliteDb.delete("_sync_history", "table_name = ?", arrayOf(localTable))

            remoteConn.createStatement().use { st ->
                st.executeQuery(query).use { rs ->
                    while (rs.next()) {
                        val values = ContentValues()
                        mappedColumns.forEachIndexed { index, (localColumn, _) ->
                            resultSetValueToContent(values, localColumn, rs.getObject(index + 1))
                        }
                        sqliteDb.insert(localTable, null, values)

                        if (localPk != null) {
                            val pkVal = values.getAsString(localPk)
                            if (pkVal != null) {
                                val h = ContentValues().apply {
                                    put("table_name", localTable)
                                    put("pk_val", pkVal)
                                }
                                sqliteDb.insert("_sync_history", null, h)
                            }
                        }
                    }
                }
            }

            sqliteDb.setTransactionSuccessful()
        } finally {
            sqliteDb.endTransaction()
        }
        return true
    }

    private fun bindCursorValue(psIndex: Int, cursor: Cursor, colIndex: Int, ps: java.sql.PreparedStatement) {
        when (cursor.getType(colIndex)) {
            Cursor.FIELD_TYPE_NULL -> ps.setObject(psIndex, null)
            Cursor.FIELD_TYPE_INTEGER -> ps.setLong(psIndex, cursor.getLong(colIndex))
            Cursor.FIELD_TYPE_FLOAT -> ps.setDouble(psIndex, cursor.getDouble(colIndex))
            Cursor.FIELD_TYPE_BLOB -> ps.setBytes(psIndex, cursor.getBlob(colIndex))
            else -> ps.setString(psIndex, cursor.getString(colIndex))
        }
    }

    private fun pushTableToRemote(
        sqliteDb: SQLiteDatabase,
        remoteConn: Connection,
        databaseName: String,
        localTable: String,
        remoteTable: String
    ): Boolean {
        val localColumns = sqliteTableColumns(sqliteDb, localTable)
        if (localColumns.isEmpty()) return false
        val remoteColumns = remoteTableColumns(remoteConn, databaseName, remoteTable)

        val mappedColumns = remoteColumns.mapNotNull { remoteColumn ->
            resolveLocalColumnName(remoteColumn, localColumns)?.let { localColumn ->
                localColumn to remoteColumn
            }
        }
        if (mappedColumns.isEmpty()) {
            if (localTableHasData(sqliteDb, localTable)) {
                throw SQLException(
                    "Aucune colonne compatible pour pousser '$localTable' vers '$remoteTable'"
                )
            }
            return false
        }

        val localPk = getLocalPrimaryKey(sqliteDb, localTable)
        val remotePkMapping = if (localPk != null) mappedColumns.find { it.first == localPk } else null

        if (localPk != null && remotePkMapping != null) {
            val remotePk = remotePkMapping.second
            val localIds = mutableSetOf<String>()
            sqliteDb.rawQuery("SELECT ${escapeIdent(localPk)} FROM ${escapeIdent(localTable)}", null).use { c ->
                if (c.moveToFirst()) {
                    do {
                        localIds.add(c.getString(0))
                    } while (c.moveToNext())
                }
            }

            val historyIds = mutableSetOf<String>()
            sqliteDb.rawQuery("SELECT pk_val FROM _sync_history WHERE table_name = ?", arrayOf(localTable)).use { c ->
                if (c.moveToFirst()) {
                    do {
                        historyIds.add(c.getString(0))
                    } while (c.moveToNext())
                }
            }

            val deletedIds = historyIds - localIds
            if (deletedIds.isNotEmpty()) {
                val inClause = deletedIds.joinToString(",") { "?" }
                val delSql = "DELETE FROM ${escapeIdent(databaseName)}.${escapeIdent(remoteTable)} WHERE ${escapeIdent(remotePk)} IN ($inClause)"
                remoteConn.prepareStatement(delSql).use { ps ->
                    var idx = 1
                    deletedIds.forEach { id ->
                        ps.setString(idx++, id)
                    }
                    ps.executeUpdate()
                }
            }

            sqliteDb.delete("_sync_history", "table_name = ?", arrayOf(localTable))
            sqliteDb.beginTransaction()
            try {
                localIds.forEach { id ->
                    val h = ContentValues().apply {
                        put("table_name", localTable)
                        put("pk_val", id)
                    }
                    sqliteDb.insert("_sync_history", null, h)
                }
                sqliteDb.setTransactionSuccessful()
            } finally {
                sqliteDb.endTransaction()
            }
        }

        val escapedColumns = mappedColumns.joinToString(", ") { (_, remoteColumn) -> escapeIdent(remoteColumn) }
        val placeholders = mappedColumns.joinToString(", ") { "?" }
        val selectColumns = mappedColumns.joinToString(", ") { (localColumn, _) -> escapeIdent(localColumn) }

        val updateClause = mappedColumns.joinToString(", ") { (_, remoteColumn) -> 
            "${escapeIdent(remoteColumn)} = VALUES(${escapeIdent(remoteColumn)})"
        }

        val insertSql = "INSERT INTO ${escapeIdent(databaseName)}.${escapeIdent(remoteTable)} ($escapedColumns) VALUES ($placeholders) ON DUPLICATE KEY UPDATE $updateClause"
        val selectSql = "SELECT $selectColumns FROM ${escapeIdent(localTable)}"

        try {
            sqliteDb.rawQuery(selectSql, null).use { cursor ->
                remoteConn.prepareStatement(insertSql).use { ps ->
                    if (cursor.moveToFirst()) {
                        do {
                            mappedColumns.indices.forEach { i ->
                                bindCursorValue(i + 1, cursor, i, ps)
                            }
                            ps.addBatch()
                        } while (cursor.moveToNext())
                    }
                    ps.executeBatch()
                }
            }
        } catch (e: SQLException) {
            throw SQLException(
                "Echec insertion table distante '$remoteTable' depuis '$localTable' : ${e.message}",
                e.sqlState,
                e.errorCode,
                e
            )
        }
        return true
    }

    fun connectAndPull(context: Context): Result<String> {
        return runCatching {
            val config = resolveConfig()
            openServerConnection(config).use { serverConn ->
                val dbName = resolveDatabaseName(context, config, serverConn)
                openDatabaseConnection(config, dbName).use { dbConn ->
                    val sqliteDb = DatabaseHelper(context).getDatabaseForMode(useExternal = true)
                    FutureRecettesManager.ensureSchema(sqliteDb)
                    val remoteNames = remoteTableNames(dbConn, dbName)
                    var synced = 0
                    syncTables.forEach { localTable ->
                        val remoteTable = resolveRemoteTableName(localTable, remoteNames)
                        if (remoteTable != null) {
                            if (pullTableFromRemote(sqliteDb, dbConn, dbName, localTable, remoteTable)) {
                                synced++
                            }
                        }
                    }
                    if (synced == 0) {
                        throw SQLException("Aucune table utilisable trouvee dans la base distante '$dbName'")
                    }
                }
                SettingsStore.setExternalDatabaseName(context, dbName)
                SettingsStore.setExternalDataSourceEnabled(context, true)
                DatabaseHelper.closeActiveDatabase()
                dbName
            }
        }
    }

    fun pushExternalToRemote(context: Context): Result<Int> {
        return runCatching {
            val config = resolveConfig()
            val dbName = SettingsStore.getExternalDatabaseName(context)
                ?: throw SQLException("Nom de base distante introuvable")

            openDatabaseConnection(config, dbName).use { dbConn ->
                dbConn.autoCommit = false
                try {
                    val sqliteDb = DatabaseHelper(context).getDatabaseForMode(useExternal = true)
                    FutureRecettesManager.ensureSchema(sqliteDb)
                    val remoteNames = remoteTableNames(dbConn, dbName)

                    val unresolvedWithData = syncTables.filter { localTable ->
                        resolveRemoteTableName(localTable, remoteNames) == null && localTableHasData(sqliteDb, localTable)
                    }
                    val unresolvedRequiredWithData = unresolvedWithData.filter { it in requiredRemoteTables }
                    if (unresolvedRequiredWithData.isNotEmpty()) {
                        throw SQLException(
                            "Tables distantes requises manquantes pour donnees locales: ${unresolvedRequiredWithData.joinToString(", ")}"
                        )
                    }

                    val resolvedTables = syncTables.mapNotNull { localTable ->
                        resolveRemoteTableName(localTable, remoteNames)?.let { remoteTable ->
                            ResolvedTable(localTable = localTable, remoteTable = remoteTable)
                        }
                    }
                    if (resolvedTables.isEmpty()) {
                        throw SQLException("Aucune table distante mappable trouvee pour '$dbName'")
                    }

                    // Delete children first to satisfy foreign keys, then insert parents first.
                    // resolvedTables.asReversed().forEach { table ->
                    //     clearRemoteTable(dbConn, dbName, table.remoteTable)
                    // }

                    var pushed = 0
                    resolvedTables.forEach { table ->
                        if (pushTableToRemote(sqliteDb, dbConn, dbName, table.localTable, table.remoteTable)) {
                            pushed++
                        }
                    }
                    if (pushed == 0) {
                        throw SQLException("Aucune table n'a pu etre synchronisee vers la base distante '$dbName'")
                    }
                    dbConn.commit()
                    pushed
                } catch (e: Exception) {
                    dbConn.rollback()
                    throw e
                } finally {
                    dbConn.autoCommit = true
                }
            }
        }
    }
}

package com.example.gestion_mobilek

import android.app.AlertDialog
import android.content.Intent
import android.database.sqlite.SQLiteException
import android.os.Bundle
import android.text.Editable
import android.text.TextWatcher
import android.view.Gravity
import android.view.View
import android.view.ViewGroup
import android.widget.*
import androidx.appcompat.app.AppCompatActivity
import androidx.swiperefreshlayout.widget.SwipeRefreshLayout

class FutureRecettesActivity : AppCompatActivity() {

    private lateinit var dbHelper: DatabaseHelper
    private lateinit var container: LinearLayout
    private lateinit var swipeRefresh: SwipeRefreshLayout
    private var selectionMode = false
    private val selectedIds = mutableSetOf<Int>()
    private var searchQuery = ""
    private var sourceConfig: FutureRecettesManager.SourceConfig? = null

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_future_recettes)

        dbHelper = DatabaseHelper(this)
        container = findViewById(R.id.containerFutureRepas)
        swipeRefresh = findViewById(R.id.swipeRefreshFuture)
        swipeRefresh.setOnRefreshListener { reloadFutureRepas() }

        findViewById<ImageButton>(R.id.btnBack).setOnClickListener { finish() }
        findViewById<ImageButton>(R.id.btnAdd).setOnClickListener {
            startActivity(Intent(this, AddEditFutureRecetteActivity::class.java))
        }
        findViewById<ImageButton>(R.id.btnSelect).setOnClickListener {
            if (selectionMode) exitSelectionMode() else enterSelectionMode()
        }
        findViewById<ImageButton>(R.id.btnDeleteSelected).setOnClickListener {
            confirmDeleteSelected()
        }

        findViewById<EditText>(R.id.etSearchFuture).addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) = Unit
            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                searchQuery = s?.toString().orEmpty().trim()
                reloadFutureRepas()
            }
            override fun afterTextChanged(s: Editable?) = Unit
        })

        refreshSourceConfig()
    }

    override fun onResume() {
        super.onResume()
        refreshSourceConfig()
        try {
            val db = dbHelper.getDatabase()
            if (sourceConfig?.isExternalMode != true) {
                FutureRecettesManager.migrateDueFutureRepas(this, db)
            }
            FutureReminderScheduler.rescheduleAll(this)
        } catch (_: SQLiteException) {
        }
        exitSelectionMode()
    }

    private fun refreshSourceConfig() {
        try {
            sourceConfig = FutureRecettesManager.resolveSourceConfig(this, dbHelper.getDatabase())
            if (sourceConfig?.isExternalMode == true) {
                FutureReminderStore.ensureSchema(dbHelper.getDatabaseForMode(false))
            } else {
                FutureRecettesManager.ensureSchema(dbHelper.getDatabase())
                FutureReminderStore.ensureSchema(dbHelper.getDatabaseForMode(false))
            }
        } catch (_: SQLiteException) {
        }
    }

    private fun enterSelectionMode() {
        selectionMode = true
        selectedIds.clear()
        findViewById<ImageButton>(R.id.btnDeleteSelected).visibility = View.VISIBLE
        findViewById<ImageButton>(R.id.btnAdd).visibility = View.GONE
        reloadFutureRepas()
    }

    private fun exitSelectionMode() {
        selectionMode = false
        selectedIds.clear()
        findViewById<ImageButton>(R.id.btnDeleteSelected).visibility = View.GONE
        findViewById<ImageButton>(R.id.btnAdd).visibility = View.VISIBLE
        reloadFutureRepas()
    }

    private fun reloadFutureRepas() {
        container.removeAllViews()
        loadFutureRepas()
    }

    private fun loadFutureRepas() {
        try {
            val db = dbHelper.getDatabase()
            val config = sourceConfig ?: FutureRecettesManager.resolveSourceConfig(this, db).also { sourceConfig = it }
            val todayStorage = DateStorageUtils.todayStorageDate()
            val todaySortable = DateStorageUtils.toSortable(todayStorage) ?: "20260416"
            val orderExpr = if (config.isStorageDate) {
                "SUBSTR(${config.dateColumn}, 5) || SUBSTR(${config.dateColumn}, 3, 2) || SUBSTR(${config.dateColumn}, 1, 2)"
            } else {
                config.dateColumn
            }

            val cursor = if (searchQuery.isBlank()) {
                if (config.isStorageDate) {
                    db.rawQuery(
                        """SELECT id, nom_plat, id_personnes, ${config.dateColumn}, description
                           FROM ${config.tableName}
                           WHERE ${config.dateColumn} IS NOT NULL AND TRIM(${config.dateColumn}) != ''
                             AND $orderExpr >= ?
                           ORDER BY $orderExpr ASC""",
                        arrayOf(todaySortable)
                    )
                } else {
                    db.rawQuery(
                        """SELECT id, nom_plat, id_personnes, ${config.dateColumn}, description
                           FROM ${config.tableName}
                           WHERE ${config.dateColumn} > 0
                           ORDER BY ${config.dateColumn} ASC""",
                        null
                    )
                }
            } else {
                val likeSearch = "%${searchQuery.lowercase()}%"
                if (config.isStorageDate) {
                    db.rawQuery(
                        """SELECT id, nom_plat, id_personnes, ${config.dateColumn}, description
                           FROM ${config.tableName}
                           WHERE ${config.dateColumn} IS NOT NULL AND TRIM(${config.dateColumn}) != ''
                             AND $orderExpr >= ?
                             AND (LOWER(nom_plat) LIKE ? OR LOWER(IFNULL(description, '')) LIKE ?)
                           ORDER BY $orderExpr ASC""",
                        arrayOf(todaySortable, likeSearch, likeSearch)
                    )
                } else {
                    db.rawQuery(
                        """SELECT id, nom_plat, id_personnes, ${config.dateColumn}, description
                           FROM ${config.tableName}
                           WHERE ${config.dateColumn} > 0
                             AND (LOWER(nom_plat) LIKE ? OR LOWER(IFNULL(description, '')) LIKE ?)
                           ORDER BY ${config.dateColumn} ASC""",
                        arrayOf(likeSearch, likeSearch)
                    )
                }
            }

            if (cursor.moveToFirst()) {
                var lastDateHeader: String? = null
                do {
                    val normalizedDate = DateStorageUtils.normalizeStorageDate(cursor.getString(3))
                    if (normalizedDate != null && normalizedDate != lastDateHeader) {
                        addDateHeader(normalizedDate)
                        lastDateHeader = normalizedDate
                    }
                    addFutureRepasRow(
                        cursor.getInt(0),
                        cursor.getString(1) ?: "",
                        cursor.getString(2) ?: "",
                        normalizedDate
                    )
                } while (cursor.moveToNext())
            } else {
                val tv = TextView(this)
                tv.text = "Aucune recette planifiée"
                tv.textSize = 16f
                tv.gravity = Gravity.CENTER
                tv.setPadding(0, 32, 0, 0)
                container.addView(tv)
            }
            cursor.close()
        } catch (e: SQLiteException) {
            Toast.makeText(this, "Erreur BDD: ${e.message}", Toast.LENGTH_LONG).show()
        } finally {
            swipeRefresh.isRefreshing = false
        }
    }

    private fun addFutureRepasRow(
        futureId: Int,
        nomPlat: String,
        idPersonnes: String,
        dateRepas: String?
    ) {
        val dateStr = DateStorageUtils.displayFromStorage(dateRepas)
        val relative = DateStorageUtils.relativeLabel(dateRepas)

        val platsList = nomPlat.split(",").filter { it.isNotBlank() }
        val platsText = when {
            platsList.isEmpty() -> "Aucun plat"
            platsList.size <= 2 -> platsList.joinToString(", ")
            else -> "${platsList[0]}, ${platsList[1]}..."
        }

        val nomsPersonnes = getPersonNames(idPersonnes)
        val noms = nomsPersonnes.split(", ").filter { it.isNotBlank() }
        val personnesText = when {
            noms.isEmpty() -> "Aucune personne"
            noms.size <= 2 -> noms.joinToString(", ")
            else -> "${noms[0]}, ${noms[1]} +${noms.size - 2}"
        }

        val row = LinearLayout(this)
        row.orientation = LinearLayout.HORIZONTAL
        row.layoutParams = LinearLayout.LayoutParams(
            ViewGroup.LayoutParams.MATCH_PARENT,
            ViewGroup.LayoutParams.WRAP_CONTENT
        ).apply { topMargin = 8; bottomMargin = 8 }
        row.gravity = Gravity.CENTER_VERTICAL

        val checkBox = CheckBox(this)
        checkBox.visibility = if (selectionMode) View.VISIBLE else View.GONE
        checkBox.isChecked = selectedIds.contains(futureId)
        checkBox.setOnCheckedChangeListener { _, checked ->
            if (checked) selectedIds.add(futureId) else selectedIds.remove(futureId)
        }

        val btn = Button(this)
        btn.layoutParams = LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.WRAP_CONTENT, 1f)
        btn.textAlignment = View.TEXT_ALIGNMENT_TEXT_START
        btn.textSize = 14f
        val dateLine = if (relative != null) " $dateStr   •   $relative" else " $dateStr"
        btn.text = "️ $platsText\n $personnesText\n$dateLine"

        btn.setOnClickListener {
            if (selectionMode) {
                checkBox.isChecked = !checkBox.isChecked
            } else {
                startActivity(Intent(this, FutureRecetteDetailActivity::class.java).apply {
                    putExtra("FUTURE_ID", futureId)
                    putExtra("SOURCE_MODE", sourceConfig?.isExternalMode?.let { if (it) 1 else 0 } ?: 0)
                })
            }
        }

        btn.setOnLongClickListener {
            if (!selectionMode) showLongPressMenu(futureId, platsText, btn)
            true
        }

        row.addView(checkBox)
        row.addView(btn)
        container.addView(row)
    }

    private fun addDateHeader(dateStorage: String) {
        val tv = TextView(this)
        val date = DateStorageUtils.displayFromStorage(dateStorage)
        val relative = DateStorageUtils.relativeLabel(dateStorage)
        tv.text = if (relative != null) "$date - $relative" else date
        tv.textSize = 13f
        tv.setTextColor(0xFF666666.toInt())
        tv.setPadding(0, 10, 0, 6)
        container.addView(tv)
    }

    private fun showLongPressMenu(futureId: Int, label: String, anchor: View) {
        val popup = PopupMenu(this, anchor, Gravity.START)
        popup.menu.add(0, 0, 0, label).apply { isEnabled = false }
        popup.menu.add(0, 1, 1, "✏️  Modifier")
        popup.menu.add(0, 2, 2, "️  Supprimer")

        popup.setOnMenuItemClickListener { item ->
            when (item.itemId) {
                1 -> startActivity(Intent(this, AddEditFutureRecetteActivity::class.java).apply {
                    putExtra("FUTURE_ID", futureId)
                    putExtra("SOURCE_MODE", sourceConfig?.isExternalMode?.let { if (it) 1 else 0 } ?: 0)
                })
                2 -> confirmDeleteOne(futureId)
            }
            true
        }
        popup.show()
    }

    private fun confirmDeleteOne(futureId: Int) {
        AlertDialog.Builder(this)
            .setTitle("Supprimer cette recette ?")
            .setMessage("Cette action est irréversible.")
            .setPositiveButton("Supprimer") { _, _ ->
                try {
                    val db = dbHelper.getDatabase()
                    val sourceMode = sourceConfig?.isExternalMode?.let { if (it) 1 else 0 } ?: 0
                    FutureReminderScheduler.cancelMealReminders(this@FutureRecettesActivity, futureId, sourceMode, deleteRows = true)
                    db.delete(sourceConfig?.tableName ?: "future_repas", "id = ?", arrayOf(futureId.toString()))
                    reloadFutureRepas()
                } catch (e: SQLiteException) {
                    Toast.makeText(this, "Erreur: ${e.message}", Toast.LENGTH_LONG).show()
                }
            }
            .setNegativeButton("Annuler", null)
            .show()
    }

    private fun confirmDeleteSelected() {
        if (selectedIds.isEmpty()) {
            Toast.makeText(this, "Aucune recette sélectionnée", Toast.LENGTH_SHORT).show()
            return
        }
        AlertDialog.Builder(this)
            .setTitle("Supprimer ${selectedIds.size} recette(s) ?")
            .setMessage("Cette action est irréversible.")
            .setPositiveButton("Supprimer") { _, _ ->
                try {
                    val db = dbHelper.getDatabase()
                    val sourceMode = sourceConfig?.isExternalMode?.let { if (it) 1 else 0 } ?: 0
                    selectedIds.forEach { id ->
                        FutureReminderScheduler.cancelMealReminders(this@FutureRecettesActivity, id, sourceMode, deleteRows = true)
                        db.delete(sourceConfig?.tableName ?: "future_repas", "id = ?", arrayOf(id.toString()))
                    }
                    Toast.makeText(this, "${selectedIds.size} recette(s) supprimée(s)", Toast.LENGTH_SHORT).show()
                    exitSelectionMode()
                } catch (e: SQLiteException) {
                    Toast.makeText(this, "Erreur: ${e.message}", Toast.LENGTH_LONG).show()
                }
            }
            .setNegativeButton("Annuler", null)
            .show()
    }

    private fun getPersonNames(idPersonnes: String): String {
        if (idPersonnes.isBlank()) return ""
        return try {
            val db = dbHelper.getDatabase()
            val ids = idPersonnes.split(",").filter { it.isNotBlank() }
            val noms = mutableListOf<String>()
            ids.forEach { id ->
                val c = db.rawQuery(
                    "SELECT nom FROM personnes WHERE id = ?",
                    arrayOf(id.trim())
                )
                if (c.moveToFirst()) noms.add(c.getString(0))
                c.close()
            }
            noms.joinToString(", ")
        } catch (_: SQLiteException) { "?" }
    }
}

package com.example.gestion_mobilek

import android.app.AlertDialog
import android.content.Intent
import android.database.sqlite.SQLiteException
import android.os.Bundle
import android.text.Editable
import android.text.TextWatcher
import android.view.Gravity
import android.view.View
import android.view.ViewGroup
import android.widget.*
import androidx.appcompat.app.AppCompatActivity
import androidx.swiperefreshlayout.widget.SwipeRefreshLayout

class FutureRecettesActivity : AppCompatActivity() {

    private lateinit var dbHelper: DatabaseHelper
    private lateinit var container: LinearLayout
    private lateinit var swipeRefresh: SwipeRefreshLayout
    private var selectionMode = false
    private val selectedIds = mutableSetOf<Int>()
    private var searchQuery = ""
    private var sourceConfig: FutureRecettesManager.SourceConfig? = null

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_future_recettes)

        dbHelper = DatabaseHelper(this)
        container = findViewById(R.id.containerFutureRepas)
        swipeRefresh = findViewById(R.id.swipeRefreshFuture)
        swipeRefresh.setOnRefreshListener { reloadFutureRepas() }

        findViewById<ImageButton>(R.id.btnBack).setOnClickListener { finish() }
        findViewById<ImageButton>(R.id.btnAdd).setOnClickListener {
            startActivity(Intent(this, AddEditFutureRecetteActivity::class.java))
        }
        findViewById<ImageButton>(R.id.btnSelect).setOnClickListener {
            if (selectionMode) exitSelectionMode() else enterSelectionMode()
        }
        findViewById<ImageButton>(R.id.btnDeleteSelected).setOnClickListener {
            confirmDeleteSelected()
        }

        findViewById<EditText>(R.id.etSearchFuture).addTextChangedListener(object : TextWatcher {
            override fun beforeTextChanged(s: CharSequence?, start: Int, count: Int, after: Int) = Unit
            override fun onTextChanged(s: CharSequence?, start: Int, before: Int, count: Int) {
                searchQuery = s?.toString().orEmpty().trim()
                reloadFutureRepas()
            }
            override fun afterTextChanged(s: Editable?) = Unit
        })

        refreshSourceConfig()
    }

    override fun onResume() {
        super.onResume()
        refreshSourceConfig()
        try {
            val db = dbHelper.getDatabase()
            if (sourceConfig?.isExternalMode != true) {
                FutureRecettesManager.migrateDueFutureRepas(this, db)
            }
            FutureReminderScheduler.rescheduleAll(this)
        } catch (_: SQLiteException) {
        }
        exitSelectionMode()
    }

    private fun refreshSourceConfig() {
        try {
            sourceConfig = FutureRecettesManager.resolveSourceConfig(this, dbHelper.getDatabase())
            if (sourceConfig?.isExternalMode == true) {
                FutureReminderStore.ensureSchema(dbHelper.getDatabaseForMode(false))
            } else {
                FutureRecettesManager.ensureSchema(dbHelper.getDatabase())
                FutureReminderStore.ensureSchema(dbHelper.getDatabaseForMode(false))
            }
        } catch (_: SQLiteException) {
        }
    }

    private fun enterSelectionMode() {
        selectionMode = true
        selectedIds.clear()
        findViewById<ImageButton>(R.id.btnDeleteSelected).visibility = View.VISIBLE
        findViewById<ImageButton>(R.id.btnAdd).visibility = View.GONE
        reloadFutureRepas()
    }

    private fun exitSelectionMode() {
        selectionMode = false
        selectedIds.clear()
        findViewById<ImageButton>(R.id.btnDeleteSelected).visibility = View.GONE
        findViewById<ImageButton>(R.id.btnAdd).visibility = View.VISIBLE
        reloadFutureRepas()
    }

    private fun reloadFutureRepas() {
        if (SettingsStore.isExternalDataSourceEnabled(this)) {
            // Pull external data before local refresh
            Thread {
                val syncResult = ExternalMariaDbSync.connectAndPull(this@FutureRecettesActivity)
                runOnUiThread {
                    if (syncResult.isFailure) {
                        Toast.makeText(this@FutureRecettesActivity, "Echec de l'actualisation distante", Toast.LENGTH_SHORT).show()
                    }
                    loadLocalData()
                }
            }.start()
        } else {
            loadLocalData()
        }
    }

    private fun loadLocalData() {
        container.removeAllViews()
        try {
            val db = dbHelper.getDatabase()
            val futureSource = FutureRecettesManager.resolveSourceConfig(this, db)
            val todayStorage = DateStorageUtils.todayStorageDate()
            val todaySortable = DateStorageUtils.toSortable(todayStorage) ?: "20260416"
            val orderExpr = if (futureSource.isStorageDate) {
                "SUBSTR(${futureSource.dateColumn}, 5) || SUBSTR(${futureSource.dateColumn}, 3, 2) || SUBSTR(${futureSource.dateColumn}, 1, 2)"
            } else {
                futureSource.dateColumn
            }

            val cursor = if (searchQuery.isBlank()) {
                if (futureSource.isStorageDate) {
                    db.rawQuery(
                        """SELECT id, nom_plat, id_personnes, ${futureSource.dateColumn}, description
                           FROM ${futureSource.tableName}
                           WHERE ${futureSource.dateColumn} IS NOT NULL AND TRIM(${futureSource.dateColumn}) != ''
                             AND $orderExpr >= ?
                           ORDER BY $orderExpr ASC""",
                        arrayOf(todaySortable)
                    )
                } else {
                    db.rawQuery(
                        """SELECT id, nom_plat, id_personnes, ${futureSource.dateColumn}, description
                           FROM ${futureSource.tableName}
                           WHERE ${futureSource.dateColumn} > 0
                           ORDER BY ${futureSource.dateColumn} ASC""",
                        null
                    )
                }
            } else {
                val likeSearch = "%${searchQuery.lowercase()}%"
                if (futureSource.isStorageDate) {
                    db.rawQuery(
                        """SELECT id, nom_plat, id_personnes, ${futureSource.dateColumn}, description
                           FROM ${futureSource.tableName}
                           WHERE ${futureSource.dateColumn} IS NOT NULL AND TRIM(${futureSource.dateColumn}) != ''
                             AND $orderExpr >= ?
                             AND (LOWER(nom_plat) LIKE ? OR LOWER(IFNULL(description, '')) LIKE ?)
                           ORDER BY $orderExpr ASC""",
                        arrayOf(todaySortable, likeSearch, likeSearch)
                    )
                } else {
                    db.rawQuery(
                        """SELECT id, nom_plat, id_personnes, ${futureSource.dateColumn}, description
                           FROM ${futureSource.tableName}
                           WHERE ${futureSource.dateColumn} > 0
                             AND (LOWER(nom_plat) LIKE ? OR LOWER(IFNULL(description, '')) LIKE ?)
                           ORDER BY ${futureSource.dateColumn} ASC""",
                        arrayOf(likeSearch, likeSearch)
                    )
                }
            }

            if (cursor.moveToFirst()) {
                var lastDateHeader: String? = null
                do {
                    val normalizedDate = DateStorageUtils.normalizeStorageDate(cursor.getString(3))
                    if (normalizedDate != null && normalizedDate != lastDateHeader) {
                        addDateHeader(normalizedDate)
                        lastDateHeader = normalizedDate
                    }
                    addFutureRepasRow(
                        cursor.getInt(0),
                        cursor.getString(1) ?: "",
                        cursor.getString(2) ?: "",
                        normalizedDate
                    )
                } while (cursor.moveToNext())
            } else {
                val tv = TextView(this)
                tv.text = "Aucune recette planifiée"
                tv.textSize = 16f
                tv.gravity = Gravity.CENTER
                tv.setPadding(0, 32, 0, 0)
                container.addView(tv)
            }
            cursor.close()
        } catch (e: SQLiteException) {
            Toast.makeText(this, "Erreur BDD: ${e.message}", Toast.LENGTH_LONG).show()
        } finally {
            swipeRefresh.isRefreshing = false
        }
    }

    private fun addFutureRepasRow(
        futureId: Int,
        nomPlat: String,
        idPersonnes: String,
        dateRepas: String?
    ) {
        val dateStr = DateStorageUtils.displayFromStorage(dateRepas)
        val relative = DateStorageUtils.relativeLabel(dateRepas)

        val platsList = nomPlat.split(",").filter { it.isNotBlank() }
        val platsText = when {
            platsList.isEmpty() -> "Aucun plat"
            platsList.size <= 2 -> platsList.joinToString(", ")
            else -> "${platsList[0]}, ${platsList[1]}..."
        }

        val nomsPersonnes = getPersonNames(idPersonnes)
        val noms = nomsPersonnes.split(", ").filter { it.isNotBlank() }
        val personnesText = when {
            noms.isEmpty() -> "Aucune personne"
            noms.size <= 2 -> noms.joinToString(", ")
            else -> "${noms[0]}, ${noms[1]} +${noms.size - 2}"
        }

        val row = LinearLayout(this)
        row.orientation = LinearLayout.HORIZONTAL
        row.layoutParams = LinearLayout.LayoutParams(
            ViewGroup.LayoutParams.MATCH_PARENT,
            ViewGroup.LayoutParams.WRAP_CONTENT
        ).apply { topMargin = 8; bottomMargin = 8 }
        row.gravity = Gravity.CENTER_VERTICAL

        val checkBox = CheckBox(this)
        checkBox.visibility = if (selectionMode) View.VISIBLE else View.GONE
        checkBox.isChecked = selectedIds.contains(futureId)
        checkBox.setOnCheckedChangeListener { _, checked ->
            if (checked) selectedIds.add(futureId) else selectedIds.remove(futureId)
        }

        val btn = Button(this)
        btn.layoutParams = LinearLayout.LayoutParams(0, ViewGroup.LayoutParams.WRAP_CONTENT, 1f)
        btn.textAlignment = View.TEXT_ALIGNMENT_TEXT_START
        btn.textSize = 14f
        val dateLine = if (relative != null) " $dateStr   •   $relative" else " $dateStr"
        btn.text = "️ $platsText\n $personnesText\n$dateLine"

        btn.setOnClickListener {
            if (selectionMode) {
                checkBox.isChecked = !checkBox.isChecked
            } else {
                startActivity(Intent(this, FutureRecetteDetailActivity::class.java).apply {
                    putExtra("FUTURE_ID", futureId)
                    putExtra("SOURCE_MODE", sourceConfig?.isExternalMode?.let { if (it) 1 else 0 } ?: 0)
                })
            }
        }

        btn.setOnLongClickListener {
            if (!selectionMode) showLongPressMenu(futureId, platsText, btn)
            true
        }

        row.addView(checkBox)
        row.addView(btn)
        container.addView(row)
    }

    private fun addDateHeader(dateStorage: String) {
        val tv = TextView(this)
        val date = DateStorageUtils.displayFromStorage(dateStorage)
        val relative = DateStorageUtils.relativeLabel(dateStorage)
        tv.text = if (relative != null) "$date - $relative" else date
        tv.textSize = 13f
        tv.setTextColor(0xFF666666.toInt())
        tv.setPadding(0, 10, 0, 6)
        container.addView(tv)
    }

    private fun showLongPressMenu(futureId: Int, label: String, anchor: View) {
        val popup = PopupMenu(this, anchor, Gravity.START)
        popup.menu.add(0, 0, 0, label).apply { isEnabled = false }
        popup.menu.add(0, 1, 1, "✏️  Modifier")
        popup.menu.add(0, 2, 2, "️  Supprimer")

        popup.setOnMenuItemClickListener { item ->
            when (item.itemId) {
                1 -> startActivity(Intent(this, AddEditFutureRecetteActivity::class.java).apply {
                    putExtra("FUTURE_ID", futureId)
                    putExtra("SOURCE_MODE", sourceConfig?.isExternalMode?.let { if (it) 1 else 0 } ?: 0)
                })
                2 -> confirmDeleteOne(futureId)
            }
            true
        }
        popup.show()
    }

    private fun confirmDeleteOne(futureId: Int) {
        AlertDialog.Builder(this)
            .setTitle("Supprimer cette recette ?")
            .setMessage("Cette action est irréversible.")
            .setPositiveButton("Supprimer") { _, _ ->
                try {
                    val db = dbHelper.getDatabase()
                    val sourceMode = sourceConfig?.isExternalMode?.let { if (it) 1 else 0 } ?: 0
                    FutureReminderScheduler.cancelMealReminders(this@FutureRecettesActivity, futureId, sourceMode, deleteRows = true)
                    db.delete(sourceConfig?.tableName ?: "future_repas", "id = ?", arrayOf(futureId.toString()))
                    reloadFutureRepas()
                } catch (e: SQLiteException) {
                    Toast.makeText(this, "Erreur: ${e.message}", Toast.LENGTH_LONG).show()
                }
            }
            .setNegativeButton("Annuler", null)
            .show()
    }

    private fun confirmDeleteSelected() {
        if (selectedIds.isEmpty()) {
            Toast.makeText(this, "Aucune recette sélectionnée", Toast.LENGTH_SHORT).show()
            return
        }
        AlertDialog.Builder(this)
            .setTitle("Supprimer ${selectedIds.size} recette(s) ?")
            .setMessage("Cette action est irréversible.")
            .setPositiveButton("Supprimer") { _, _ ->
                try {
                    val db = dbHelper.getDatabase()
                    val sourceMode = sourceConfig?.isExternalMode?.let { if (it) 1 else 0 } ?: 0
                    selectedIds.forEach { id ->
                        FutureReminderScheduler.cancelMealReminders(this@FutureRecettesActivity, id, sourceMode, deleteRows = true)
                        db.delete(sourceConfig?.tableName ?: "future_repas", "id = ?", arrayOf(id.toString()))
                    }
                    Toast.makeText(this, "${selectedIds.size} recette(s) supprimée(s)", Toast.LENGTH_SHORT).show()
                    exitSelectionMode()
                } catch (e: SQLiteException) {
                    Toast.makeText(this, "Erreur: ${e.message}", Toast.LENGTH_LONG).show()
                }
            }
            .setNegativeButton("Annuler", null)
            .show()
    }

    private fun getPersonNames(idPersonnes: String): String {
        if (idPersonnes.isBlank()) return ""
        return try {
            val db = dbHelper.getDatabase()
            val ids = idPersonnes.split(",").filter { it.isNotBlank() }
            val noms = mutableListOf<String>()
            ids.forEach { id ->
                val c = db.rawQuery(
                    "SELECT nom FROM personnes WHERE id = ?",
                    arrayOf(id.trim())
                )
                if (c.moveToFirst()) noms.add(c.getString(0))
                c.close()
            }
            noms.joinToString(", ")
        } catch (_: SQLiteException) { "?" }
    }
}

package com.example.gestion_mobilek

import android.content.Context
import android.content.ContentValues
import android.database.sqlite.SQLiteDatabase
import android.database.sqlite.SQLiteException

object FutureRecettesManager {

    private const val FUTURE_TABLE = "future_repas"
    const val NEW_DATE_COL = "date_dernier_repas"
    const val LEGACY_DATE_COL = "date_repas"

    data class SourceConfig(
        val tableName: String,
        val dateColumn: String,
        val isStorageDate: Boolean,
        val isExternalMode: Boolean
    )

    private fun dateSortExpr(column: String): String {
        return "substr(printf('%08d', CAST($column AS INTEGER)), 5, 4) || " +
            "substr(printf('%08d', CAST($column AS INTEGER)), 3, 2) || " +
            "substr(printf('%08d', CAST($column AS INTEGER)), 1, 2)"
    }

    fun ensureSchema(db: SQLiteDatabase) {
        db.execSQL(
            """
            CREATE TABLE IF NOT EXISTS $FUTURE_TABLE (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                nom_plat TEXT NOT NULL,
                id_personnes TEXT,
                $NEW_DATE_COL TEXT NOT NULL,
                description TEXT
            )
            """.trimIndent()
        )
    }

    fun resolveDateColumn(db: SQLiteDatabase): String {
        ensureSchema(db)
        val cols = mutableSetOf<String>()
        db.rawQuery("PRAGMA table_info($FUTURE_TABLE)", null).use { c ->
            if (c.moveToFirst()) {
                do {
                    cols.add(c.getString(1))
                } while (c.moveToNext())
            }
        }

        return when {
            cols.contains(NEW_DATE_COL) -> NEW_DATE_COL
            cols.contains(LEGACY_DATE_COL) -> LEGACY_DATE_COL
            else -> {
                db.execSQL("ALTER TABLE $FUTURE_TABLE ADD COLUMN $NEW_DATE_COL TEXT")
                NEW_DATE_COL
            }
        }
    }

    fun resolveSourceConfig(context: Context, db: SQLiteDatabase): SourceConfig {
        return SourceConfig(
            tableName = FUTURE_TABLE,
            dateColumn = resolveDateColumn(db),
            isStorageDate = true,
            isExternalMode = SettingsStore.isExternalDataSourceEnabled(context)
        )
    }

    fun resolveSourceTable(context: Context): String {
        return FUTURE_TABLE
    }

    fun migrateDueFutureRepas(context: Context, db: SQLiteDatabase) {
        if (SettingsStore.isExternalDataSourceEnabled(context)) return
        ensureSchema(db)
        val repasDateConfig = RepasDateCompat.resolve(db)
        val futureDateCol = resolveDateColumn(db)

        val todaySortable = DateStorageUtils.toSortable(DateStorageUtils.todayStorageDate()) ?: return
        val orderExpr = "SUBSTR($futureDateCol, 5) || SUBSTR($futureDateCol, 3, 2) || SUBSTR($futureDateCol, 1, 2)"

        try {
            val dueMeals = mutableListOf<ContentValues>()
            val dueIds = mutableListOf<Int>()

            val cursor = db.rawQuery(
                """SELECT id, nom_plat, id_personnes, $futureDateCol, description
                   FROM future_repas
                   WHERE $futureDateCol IS NOT NULL AND TRIM($futureDateCol) != ''
                     AND $orderExpr < ?""",
                arrayOf(todaySortable)
            )

            if (cursor.moveToFirst()) {
                do {
                    dueIds.add(cursor.getInt(0))
                    dueMeals.add(ContentValues().apply {
                        put("nom_plat", cursor.getString(1) ?: "")
                        put("id_personnes", cursor.getString(2) ?: "")
                        val rawDate = cursor.getString(3)
                        if (repasDateConfig.isStorageDate) {
                            put(repasDateConfig.columnName, DateStorageUtils.normalizeStorageDate(rawDate) ?: "")
                        } else {
                            put(repasDateConfig.columnName, DateStorageUtils.toLegacyDaysAgo(rawDate) ?: 0)
                        }
                        put("description", cursor.getString(4) ?: "")
                    })
                } while (cursor.moveToNext())
            }
            cursor.close()

            if (dueIds.isEmpty()) return

            dueIds.forEach { futureId ->
                FutureReminderScheduler.cancelMealReminders(context, futureId, 0, deleteRows = true)
            }

            db.beginTransaction()
            try {
                dueMeals.forEach { meal ->
                    db.insert("repas", null, meal)
                }
                dueIds.forEach { id ->
                    db.delete(FUTURE_TABLE, "id = ?", arrayOf(id.toString()))
                }
                dueMeals.forEach { meal ->
                    val idPersonnagesRaw = meal.getAsString("id_personnes") ?: ""
                    val personIds = idPersonnagesRaw.split(",").mapNotNull { it.trim().toIntOrNull() }
                    val mealDate = meal.getAsString(repasDateConfig.columnName) ?: ""
                    personIds.forEach { personId ->
                        val personCursor = db.rawQuery(
                            "SELECT dernier_passage FROM personnes WHERE id = ?",
                            arrayOf(personId.toString())
                        )
                        var shouldUpdate = true
                        if (personCursor.moveToFirst()) {
                            val existingDate = personCursor.getString(0)
                            if (!existingDate.isNullOrBlank()) {
                                val mealSort = if (repasDateConfig.isStorageDate) {
                                    DateStorageUtils.toSortable(mealDate) ?: ""
                                } else {
                                    val asStorage = DateStorageUtils.normalizeStorageDate(mealDate.toIntOrNull()?.toString() ?: "")
                                    DateStorageUtils.toSortable(asStorage) ?: ""
                                }
                                val existingSort = if (repasDateConfig.isStorageDate) {
                                    DateStorageUtils.toSortable(existingDate) ?: ""
                                } else {
                                    val asStorage = DateStorageUtils.normalizeStorageDate(existingDate.toIntOrNull()?.toString() ?: "")
                                    DateStorageUtils.toSortable(asStorage) ?: ""
                                }
                                shouldUpdate = mealSort > existingSort
                            }
                        }
                        personCursor.close()

                        if (shouldUpdate) {
                            val updateValues = ContentValues().apply {
                                put("dernier_passage", mealDate)
                            }
                            db.update("personnes", updateValues, "id = ?", arrayOf(personId.toString()))
                        }
                    }
                }
                db.setTransactionSuccessful()
            } finally {
                db.endTransaction()
            }
        } catch (_: SQLiteException) {
            // Ne bloque pas l'app si migration impossible temporairement
        }
    }
}

package com.example.gestion_mobilek

import android.content.Context
import android.content.ContentValues
import android.database.sqlite.SQLiteDatabase
import android.database.sqlite.SQLiteException

object FutureRecettesManager {

    private const val FUTURE_TABLE = "future_repas"
    const val NEW_DATE_COL = "date_dernier_repas"
    const val LEGACY_DATE_COL = "date_repas"

    data class SourceConfig(
        val tableName: String,
        val dateColumn: String,
        val isStorageDate: Boolean,
        val isExternalMode: Boolean
    )

    private fun dateSortExpr(column: String): String {
        return "substr(printf('%08d', CAST($column AS INTEGER)), 5, 4) || " +
            "substr(printf('%08d', CAST($column AS INTEGER)), 3, 2) || " +
            "substr(printf('%08d', CAST($column AS INTEGER)), 1, 2)"
    }

    fun ensureSchema(db: SQLiteDatabase) {
        db.execSQL(
            """
            CREATE TABLE IF NOT EXISTS $FUTURE_TABLE (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                nom_plat TEXT NOT NULL,
                id_personnes TEXT,
                $NEW_DATE_COL TEXT NOT NULL,
                description TEXT
            )
            """.trimIndent()
        )
        db.execSQL(
            """
            CREATE TABLE IF NOT EXISTS _sync_history (
                table_name TEXT,
                pk_val TEXT,
                PRIMARY KEY (table_name, pk_val)
            )
            """.trimIndent()
        )
    }

    fun resolveDateColumn(db: SQLiteDatabase): String {
        ensureSchema(db)
        val cols = mutableSetOf<String>()
        db.rawQuery("PRAGMA table_info($FUTURE_TABLE)", null).use { c ->
            if (c.moveToFirst()) {
                do {
                    cols.add(c.getString(1))
                } while (c.moveToNext())
            }
        }

        return when {
            cols.contains(NEW_DATE_COL) -> NEW_DATE_COL
            cols.contains(LEGACY_DATE_COL) -> LEGACY_DATE_COL
            else -> {
                db.execSQL("ALTER TABLE $FUTURE_TABLE ADD COLUMN $NEW_DATE_COL TEXT")
                NEW_DATE_COL
            }
        }
    }

    fun resolveSourceConfig(context: Context, db: SQLiteDatabase): SourceConfig {
        return SourceConfig(
            tableName = FUTURE_TABLE,
            dateColumn = resolveDateColumn(db),
            isStorageDate = true,
            isExternalMode = SettingsStore.isExternalDataSourceEnabled(context)
        )
    }

    fun resolveSourceTable(context: Context): String {
        return FUTURE_TABLE
    }

    fun migrateDueFutureRepas(context: Context, db: SQLiteDatabase) {
        if (SettingsStore.isExternalDataSourceEnabled(context)) return
        ensureSchema(db)
        val repasDateConfig = RepasDateCompat.resolve(db)
        val futureDateCol = resolveDateColumn(db)

        val todaySortable = DateStorageUtils.toSortable(DateStorageUtils.todayStorageDate()) ?: return
        val orderExpr = "SUBSTR($futureDateCol, 5) || SUBSTR($futureDateCol, 3, 2) || SUBSTR($futureDateCol, 1, 2)"

        try {
            val dueMeals = mutableListOf<ContentValues>()
            val dueIds = mutableListOf<Int>()

            val cursor = db.rawQuery(
                """SELECT id, nom_plat, id_personnes, $futureDateCol, description
                   FROM future_repas
                   WHERE $futureDateCol IS NOT NULL AND TRIM($futureDateCol) != ''
                     AND $orderExpr < ?""",
                arrayOf(todaySortable)
            )

            if (cursor.moveToFirst()) {
                do {
                    dueIds.add(cursor.getInt(0))
                    dueMeals.add(ContentValues().apply {
                        put("nom_plat", cursor.getString(1) ?: "")
                        put("id_personnes", cursor.getString(2) ?: "")
                        val rawDate = cursor.getString(3)
                        if (repasDateConfig.isStorageDate) {
                            put(repasDateConfig.columnName, DateStorageUtils.normalizeStorageDate(rawDate) ?: "")
                        } else {
                            put(repasDateConfig.columnName, DateStorageUtils.toLegacyDaysAgo(rawDate) ?: 0)
                        }
                        put("description", cursor.getString(4) ?: "")
                    })
                } while (cursor.moveToNext())
            }
            cursor.close()

            if (dueIds.isEmpty()) return

            dueIds.forEach { futureId ->
                FutureReminderScheduler.cancelMealReminders(context, futureId, 0, deleteRows = true)
            }

            db.beginTransaction()
            try {
                dueMeals.forEach { meal ->
                    db.insert("repas", null, meal)
                }
                dueIds.forEach { id ->
                    db.delete(FUTURE_TABLE, "id = ?", arrayOf(id.toString()))
                }
                dueMeals.forEach { meal ->
                    val idPersonnagesRaw = meal.getAsString("id_personnes") ?: ""
                    val personIds = idPersonnagesRaw.split(",").mapNotNull { it.trim().toIntOrNull() }
                    val mealDate = meal.getAsString(repasDateConfig.columnName) ?: ""
                    personIds.forEach { personId ->
                        val personCursor = db.rawQuery(
                            "SELECT dernier_passage FROM personnes WHERE id = ?",
                            arrayOf(personId.toString())
                        )
                        var shouldUpdate = true
                        if (personCursor.moveToFirst()) {
                            val existingDate = personCursor.getString(0)
                            if (!existingDate.isNullOrBlank()) {
                                val mealSort = if (repasDateConfig.isStorageDate) {
                                    DateStorageUtils.toSortable(mealDate) ?: ""
                                } else {
                                    val asStorage = DateStorageUtils.normalizeStorageDate(mealDate.toIntOrNull()?.toString() ?: "")
                                    DateStorageUtils.toSortable(asStorage) ?: ""
                                }
                                val existingSort = if (repasDateConfig.isStorageDate) {
                                    DateStorageUtils.toSortable(existingDate) ?: ""
                                } else {
                                    val asStorage = DateStorageUtils.normalizeStorageDate(existingDate.toIntOrNull()?.toString() ?: "")
                                    DateStorageUtils.toSortable(asStorage) ?: ""
                                }
                                shouldUpdate = mealSort > existingSort
                            }
                        }
                        personCursor.close()

                        if (shouldUpdate) {
                            val updateValues = ContentValues().apply {
                                put("dernier_passage", mealDate)
                            }
                            db.update("personnes", updateValues, "id = ?", arrayOf(personId.toString()))
                        }
                    }
                }
                db.setTransactionSuccessful()
            } finally {
                db.endTransaction()
            }
        } catch (_: SQLiteException) {
            // Ne bloque pas l'app si migration impossible temporairement
        }
    }
}

package com.example.gestion_mobilek

import android.content.Intent
import android.database.sqlite.SQLiteException
import android.os.Build
import android.os.Bundle
import android.view.ViewGroup
import android.widget.*
import androidx.appcompat.app.AppCompatActivity
import androidx.appcompat.app.AppCompatDelegate
import com.example.gestion_mobilek.databinding.ActivityMainBinding
import com.google.android.material.bottomsheet.BottomSheetBehavior

class MainActivity : AppCompatActivity() {

    private lateinit var binding: ActivityMainBinding
    private lateinit var dbHelper: DatabaseHelper
    private lateinit var bottomSheetBehavior: BottomSheetBehavior<LinearLayout>
    @Volatile
    private var connectionBusy = false

    override fun onCreate(savedInstanceState: Bundle?) {
        AppCompatDelegate.setDefaultNightMode(AppCompatDelegate.MODE_NIGHT_NO)
        super.onCreate(savedInstanceState)
        binding = ActivityMainBinding.inflate(layoutInflater)
        setContentView(binding.root)

        if (Build.VERSION.SDK_INT >= 33 && checkSelfPermission(android.Manifest.permission.POST_NOTIFICATIONS) != android.content.pm.PackageManager.PERMISSION_GRANTED) {
            requestPermissions(arrayOf(android.Manifest.permission.POST_NOTIFICATIONS), 4201)
        }

        dbHelper = DatabaseHelper(this)

        setupBottomSheet()

        binding.btnPlats.setOnClickListener {
            startActivity(Intent(this, ItemListActivity::class.java).apply {
                putExtra("TYPE", "plat")
            })
        }
        binding.btnPersonnes.setOnClickListener {
            startActivity(Intent(this, PersonListActivity::class.java))
        }
        binding.btnIngredients.setOnClickListener {
            startActivity(Intent(this, ItemListActivity::class.java).apply {
                putExtra("TYPE", "ingredient")
            })
        }
        binding.btnFutureRecettes.setOnClickListener {
            startActivity(Intent(this, FutureRecettesActivity::class.java))
        }
        binding.btnHistorique.setOnClickListener {
            startActivity(Intent(this, HistoriqueActivity::class.java))
        }
        binding.btnMenu.setOnClickListener {
            PopupMenu(this, binding.btnMenu).apply {
                this@MainActivity.menuInflater.inflate(R.menu.main_activity_menu, menu)
                setOnMenuItemClickListener { item ->
                    when (item.itemId) {
                        R.id.action_settings -> {
                            startActivity(Intent(this@MainActivity, SettingsActivity::class.java))
                            true
                        }
                        R.id.action_license -> {
                            startActivity(Intent(this@MainActivity, SettingsActivity::class.java).apply {
                                putExtra("OPEN_LICENSE", true)
                            })
                            true
                        }
                        R.id.action_about -> {
                            startActivity(Intent(this@MainActivity, SettingsActivity::class.java).apply {
                                putExtra("OPEN_ABOUT", true)
                            })
                            true
                        }
                        else -> false
                    }
                }
                show()
            }
        }

        binding.btnConnectExternal.setOnClickListener {
            if (connectionBusy) return@setOnClickListener
            if (SettingsStore.isExternalDataSourceEnabled(this)) {
                switchBackToLocal()
            } else {
                connectToExternalSource()
            }
        }

        refreshDataSourceUi()

        if (SettingsStore.shouldKeepExternalMode(this) && !SettingsStore.isExternalDataSourceEnabled(this)) {
            connectToExternalSource(auto = true)
        }
    }

    override fun onResume() {
        super.onResume()
        try {
            FutureRecettesManager.migrateDueFutureRepas(this, dbHelper.getDatabase())
            FutureReminderScheduler.rescheduleAll(this)
        } catch (_: SQLiteException) {
        }
        refreshDataSourceUi()
        if (!connectionBusy && SettingsStore.shouldKeepExternalMode(this) && !SettingsStore.isExternalDataSourceEnabled(this)) {
            connectToExternalSource(auto = true)
        }
        binding.containerLastMeals.post {
            loadLastMeals()
        }
    }

    private fun setConnectionBusy(busy: Boolean) {
        connectionBusy = busy
        setHomeButtonsEnabled(!busy)
        if (busy) {
            binding.btnConnectExternal.text = getString(R.string.home_connecting)
        } else {
            refreshDataSourceUi()
        }
    }

    private fun setHomeButtonsEnabled(enabled: Boolean) {
        val views = listOf(
            binding.btnMenu,
            binding.btnIngredients,
            binding.btnFutureRecettes,
            binding.btnPersonnes,
            binding.btnPlats,
            binding.btnHistorique,
        )
        views.forEach { view ->
            view.isEnabled = enabled
            view.alpha = if (enabled) 1f else 0.45f
        }
        binding.btnConnectExternal.isEnabled = true
        binding.btnConnectExternal.isClickable = enabled
        binding.btnConnectExternal.isFocusable = enabled
        binding.btnConnectExternal.alpha = 1f
        binding.bottomSheet.isEnabled = enabled
        binding.bottomSheet.isClickable = enabled
    }

    private fun refreshDataSourceUi() {
        val external = SettingsStore.isExternalDataSourceEnabled(this)
        if (external) {
            binding.btnConnectExternal.text = getString(R.string.home_disconnect_external)
            val dbName = SettingsStore.getExternalDatabaseName(this) ?: "?"
            binding.tvDataSourceStatus.text = getString(R.string.home_data_source_external, dbName)
        } else {
            binding.btnConnectExternal.text = getString(R.string.home_connect_external)
            binding.tvDataSourceStatus.text = getString(R.string.home_data_source_local)
        }
    }

    private fun connectToExternalSource(auto: Boolean = false) {
        if (connectionBusy) return
        setConnectionBusy(true)
        Thread {
            val result = ExternalMariaDbSync.connectAndPull(applicationContext)
            runOnUiThread {
                setConnectionBusy(false)
                result
                    .onSuccess { dbName ->
                        if (!auto) {
                            Toast.makeText(this, getString(R.string.home_external_connected, dbName), Toast.LENGTH_LONG).show()
                        }
                        loadLastMeals()
                    }
                    .onFailure { e ->
                        if (!auto) {
                            Toast.makeText(this, getString(R.string.home_external_connection_failed, e.message ?: "?"), Toast.LENGTH_LONG).show()
                        }
                    }
            }
        }.start()
    }

    private fun switchBackToLocal() {
        setConnectionBusy(true)
        Thread {
            val pushResult = ExternalSyncManager.pushToRemote(applicationContext)
            runOnUiThread {
                setConnectionBusy(false)
                // Always switch to local mode, even if remote push fails.
                SettingsStore.setExternalDataSourceEnabled(applicationContext, false)
                SettingsStore.setKeepExternalMode(applicationContext, false)
                DatabaseHelper.closeActiveDatabase()

                pushResult
                    .onSuccess {
                        Toast.makeText(this, getString(R.string.home_returned_local), Toast.LENGTH_SHORT).show()
                    }
                    .onFailure { e ->
                        val details = e.message?.takeIf { it.isNotBlank() } ?: "?"
                        Toast.makeText(
                            this,
                            getString(R.string.home_returned_local_unsynced) + " : " + details,
                            Toast.LENGTH_LONG
                        ).show()
                    }
                loadLastMeals()
            }
        }.start()
    }

    // ─── BOTTOM SHEET ───────────────────────────────────────────────

    private fun setupBottomSheet() {
        bottomSheetBehavior = BottomSheetBehavior.from(binding.bottomSheet)
        bottomSheetBehavior.peekHeight = dpToPx(80)
        bottomSheetBehavior.state = BottomSheetBehavior.STATE_COLLAPSED
        bottomSheetBehavior.isHideable = false

        val screenHeight = resources.displayMetrics.heightPixels
        val maxHeight = screenHeight / 2

        binding.bottomSheet.post {
            val params = binding.bottomSheet.layoutParams
            params.height = maxHeight
            binding.bottomSheet.layoutParams = params
        }
    }

    private fun dpToPx(dp: Int): Int =
        (dp * resources.displayMetrics.density).toInt()

    private fun updateStatsFromDB() {
        try {
            dbHelper.getDatabase()
        } catch (_: SQLiteException) { /* silencieux */ }
    }

    // ─── 3 DERNIERS REPAS ───────────────────────────────────────────

    private fun loadLastMeals() {
        binding.containerLastMeals.removeAllViews()
        try {
            val db = dbHelper.getDatabase()
            val dateConfig = RepasDateCompat.resolve(db)
            val cursor = if (dateConfig.isStorageDate) {
                val todayStorage = DateStorageUtils.todayStorageDate()
                val todaySortable = DateStorageUtils.toSortable(todayStorage) ?: "20260416"
                val orderExpr = "SUBSTR(${dateConfig.columnName}, 5) || SUBSTR(${dateConfig.columnName}, 3, 2) || SUBSTR(${dateConfig.columnName}, 1, 2)"
                db.rawQuery(
                    """SELECT id, nom_plat, id_personnes, ${dateConfig.columnName}
                       FROM repas
                       WHERE ${dateConfig.columnName} IS NOT NULL AND TRIM(${dateConfig.columnName}) != ''
                         AND $orderExpr < ?
                       ORDER BY $orderExpr DESC
                       LIMIT 3""",
                    arrayOf(todaySortable)
                )
            } else {
                db.rawQuery(
                    """SELECT id, nom_plat, id_personnes, ${dateConfig.columnName}
                       FROM repas
                       WHERE ${dateConfig.columnName} > 0
                       ORDER BY ${dateConfig.columnName} ASC
                       LIMIT 3""",
                    null
                )
            }
            if (cursor.moveToFirst()) {
                do {
                    addLastMealRow(
                        cursor.getInt(0),
                        cursor.getString(1) ?: "",
                        cursor.getString(2) ?: "",
                        RepasDateCompat.cursorDateAsStorage(dateConfig, cursor.getString(3))
                    )
                } while (cursor.moveToNext())
            } else {
                val tv = TextView(this)
                tv.text = "Aucun repas passé"
                tv.textSize = 14f
                tv.setTextColor(0xFFAAAAAA.toInt())
                tv.setPadding(0, 8, 0, 8)
                binding.containerLastMeals.addView(tv)
            }
            cursor.close()
        } catch (e: SQLiteException) { /* silencieux */ }
    }

    private fun addLastMealRow(
        repasId: Int,
        nomPlat: String,
        idPersonnes: String,
        dateDernierRepas: String?
    ) {
        val dateStr = DateStorageUtils.displayFromStorage(dateDernierRepas)

        // Plats CSV : max 2 affichés
        val platsList = nomPlat.split(",").filter { it.isNotBlank() }
        val platsText = when {
            platsList.isEmpty() -> "Aucun plat"
            platsList.size <= 2 -> platsList.joinToString(", ")
            else -> "${platsList[0]}, ${platsList[1]}..."
        }

        // Personnes : max 2 affichées
        val nomsPersonnes = getPersonNames(idPersonnes)
        val noms = nomsPersonnes.split(", ").filter { it.isNotBlank() }
        val personnesText = when {
            noms.isEmpty() -> "Aucune personne"
            noms.size <= 2 -> noms.joinToString(", ")
            else -> "${noms[0]}, ${noms[1]} +${noms.size - 2}"
        }

        val btn = Button(this)
        btn.layoutParams = LinearLayout.LayoutParams(
            ViewGroup.LayoutParams.MATCH_PARENT,
            ViewGroup.LayoutParams.WRAP_CONTENT
        ).apply { topMargin = 4; bottomMargin = 4 }
        btn.textSize = 13f
        btn.textAlignment = android.view.View.TEXT_ALIGNMENT_TEXT_START
        btn.text = "️ $platsText\n $personnesText\n $dateStr"
        btn.setTextColor(0xFFFFFFFF.toInt())
        btn.setBackgroundColor(0xFF2A2A2A.toInt())
        btn.setOnClickListener {
            startActivity(Intent(this, HistoriqueActivity::class.java))
        }
        binding.containerLastMeals.addView(btn)
    }


    private fun getPersonNames(idPersonnes: String): String {
        if (idPersonnes.isBlank()) return ""
        return try {
            val db = dbHelper.getDatabase()
            val ids = idPersonnes.split(",").filter { it.isNotBlank() }
            val noms = mutableListOf<String>()
            ids.forEach { id ->
                val c = db.rawQuery(
                    "SELECT nom FROM personnes WHERE id = ?",
                    arrayOf(id.trim())
                )
                if (c.moveToFirst()) noms.add(c.getString(0))
                c.close()
            }
            noms.joinToString(", ")
        } catch (e: SQLiteException) { "?" }
    }
}

